const post = $input.first().json.data || {};
const caption = post.caption || 'Henüz caption üretilmedi';
const platforms = (post.platforms || []).join(', ') || 'Belirtilmemiş';
const outputUrl = post.output_url || post.thumbnail_url || null;
const contentType = post.content_type || 'image';
const isVideo = contentType === 'video';

const messageText = `📱 *Yeni İçerik Onayı*\n\n${caption.substring(0,200)}\n\nPlatformlar: ${platforms}\nTip: ${isVideo ? 'Video' : 'Görsel'}${outputUrl && isVideo ? '\n\n🎬 [Videoyu İzle](' + outputUrl + ')' : ''}\n\nOnaylıyor musunuz?`;

return [{
  json: {
    post_id: $('Onay İsteği Webhook').item.json.body.post_id,
    caption: caption.substring(0, 200),
    platforms,
    image_url: outputUrl,
    content_type: contentType,
    is_video: isVideo,
    message: messageText
  }
}];
